After install

$ sesearch -A -s sshd_t -t container_runtime_exec_t
allow domain file_type:blk_file map; [ domain_can_mmap_files ]:True
allow domain file_type:chr_file map; [ domain_can_mmap_files ]:True
allow domain file_type:file map; [ domain_can_mmap_files ]:True
allow domain file_type:lnk_file map; [ domain_can_mmap_files ]:True
allow login_pgm exec_type:file getattr;
**allow sshd_t container_runtime_exec_t:file { execute ioctl map open read };**
allow sshd_t file_type:dir { getattr open search };
allow sshd_t file_type:filesystem getattr;

$ sesearch -A -s sshd_t -t container_runtime_t
allow daemon daemon:unix_stream_socket connectto; [ daemons_enable_cluster_mode ]:True
allow domain domain:anon_inode { create getattr ioctl map read write };
allow domain domain:fd use; [ domain_fd_use ]:True
allow domain domain:key { link search };
allow domain unconfined_domain_type:association recvfrom;
allow domain unconfined_domain_type:peer recv;
allow domain unconfined_domain_type:tcp_socket recvfrom;
allow login_pgm domain:dir { getattr ioctl lock open read search };
allow login_pgm domain:file { getattr ioctl lock open read };
allow login_pgm domain:lnk_file { getattr read };
allow login_pgm domain:process sigkill;
allow login_pgm nsswitch_domain:key { create read setattr view write };
**allow sshd_t container_runtime_t:process transition;**

Which means the podman process will run as container_runtime_t rather then sshd_t.

This appears to work

```selinux
policy_module(gitea-sshd,0.1)

gen_require(`
        type sshd_t;
	type iptables_var_run_t;
	type systemd_logind_t;
	class dir read;
')

container_runtime_domtrans(sshd_t)
allow systemd_logind_t iptables_var_run_t:dir read;
```
